var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"여기가 내가 사는 마을 시린그라드야!","JPN":"ここが私が住んでいる村、シリングラードだよ！","ENG":"This is Ciringrad, the village I live in!","TWN":"這裡就是我住的村子，錫林格勒！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"쬐~끔 빈곤하고 춥긴 해도, 세상 어느곳보다 따뜻한 사람들이 모여있다구!","JPN":"ちょ～っと貧しくて寒いとこだけど、住人たちはどの村よりも温かい人ばかりだから！","ENG":"It's very very little poor and cold, but the people here are the warmest you'll ever meet!","TWN":"雖然有點破有點冷，但這裡的人比世界上任何地方的人都溫暖！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"왜 그래?","JPN":"どうしたの？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"따뜻한 시선들이 가득하네.","JPN":"温かい視線がいっぱいね。","ENG":"I'm getting a lot of hot gazes.","TWN":"溫暖到有些灼熱的目光……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"크흠! 외지인을 경계하는 것뿐이니까 괜찮아.","JPN":"ご、ごほん……！　外部の人ってことでちょっと警戒してるだけだから、大丈夫だよ。","ENG":"Ahem! They're just cautious about outsiders. Don't worry.","TWN":"咳咳！他們只是對外人有些警惕，沒關係的。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"북방합의체에 소속된 마을이지만 사실상 유배지나 다름없는 마을이거든.","JPN":"一応北方合意体に所属しているけど、実際は流刑地のような村なの。","ENG":"The village is a part of the Northern Union, but in truth, it's more of a place of exile.","TWN":"雖然名義上是北方和議會的一部分，但實際上和邊疆地帶沒什麼兩樣。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"북방의 체제에서 도망치거나 추방된 사람들이 모여 세운 마을이지.","JPN":"北方の体制から逃げたり、追放されたりした人々が集まってるんだ。","ENG":"It's a village made by people who fled the Northern Union regime or were exiled by them.","TWN":"這是由被北方和議會驅逐，或者單純逃離那裡的人們建立的村子。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그래도 내가 있어서 다행이지 않아? 아마 너 혼자였으면 몰매를 맞았을지도 몰라.","JPN":"でも、私と一緒でよかったね！　あなた一人だったら袋叩きにされたかも。","ENG":"But you're lucky that I'm with you. If you came here alone, you could've been beaten by them.","TWN":"不過有我在，是不是很幸運？要是你一個人來的話，可能會被蓋布袋喔。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"네가 있었기 때문에 여길 오게 된 거지만 말이야.","JPN":"あなたと一緒だったから、ここに来ることになったわけだけどね。","ENG":"I'm only here because of you, though.","TWN":"可是我會來這裡是因為你。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아하하. 그건 그렇네.","JPN":"あはは、それはそうだ。","ENG":"Ah hah hah, that's also true.","TWN":"啊哈哈，那倒是……"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"나도 처음 이곳에 왔을 때 힘들긴 했지만, 분명 너도 잘 적응할 수 있을 거야.","JPN":"私も初めてこの村に来た頃は苦労したけど、あなたならすぐに慣れるよ。","ENG":"It was hard for me too when I first came here, but I'm certain that you'll adjust in no time.","TWN":"我剛來這裡的時候也很辛苦，但我相信你也能適應的。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"나중에 내가 아는 사람들은 모두 소개시켜 줄게.","JPN":"後で知り合いも紹介してあげるね。","ENG":"I'll introduce you to everyone I know later.","TWN":"以後我會把我認識的人都介紹給你。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너도 이곳 사람이 아니었던 거야?","JPN":"あなたもこの村出身じゃなかったの？","ENG":"You weren't originally from here?","TWN":"你……不也是這裡的人嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응. 나도 이곳에 온 지는 몇 년밖에 안 됐어.","JPN":"うん。私も定着してまだ数年ちょっと。","ENG":"Nope. I've only been here for a couple of years now.","TWN":"嗯……我來這裡也才幾年而已。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"난 <color=#ffd34c>떠돌이</color>였거든. 유일하게 가진 건 사샤라는 이름뿐이었지.","JPN":"前は<color=#ffd34c>流れ者</color>だったんだ。持ってるものは、サシャって名前一つだけ。","ENG":"I was a <color=#ffd34c>wanderer</color>. And the only thing I had was my name, Sasha.","TWN":"我是個<color=#ffd34c>浪人</color>。唯一擁有的就是莎夏這個名字。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"자자. 우울한 이야기는 그만두고, 보리스 아저씨한테 볼일이 있는데 거기부터 가자.","JPN":"はい、暗い話は終わり！　ボリスおじさんに用があるから、まずそっちに行こう。","ENG":"Now! Enough with the gloomy stuff, and let's go see Boris. I have some business to take care of with him.","TWN":"好了好了，別再說這些傷感的事了，我有事要找布里斯大叔，先去那邊吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그 자동차를 빌려줬다는 사람?","JPN":"前に車を貸してくれた人？","ENG":"You mean the person who lent you the car?","TWN":"就是那個借你車的人？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"맞아! 그 아저씨는 내 단골이거든.","JPN":"そう！　私の常連さんでね。","ENG":"Yup! He's one of my regulars.","TWN":"是啊！那個大叔是我的常客。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이 고물을 주문한 사람이 그 아저씨니까 들렀다 가자.","JPN":"この古鉄を注文したのもそのおじさんなの。","ENG":"He's actually the one who ordered all this junk, so let's go see him.","TWN":"這堆破銅爛鐵是他訂的，我們去看看吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아저씨~ 저 왔어요!","JPN":"ボリスさ～ん、ただいま！","ENG":"Boris! I'm back!","TWN":"大叔～我回來了！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"이제야 왔군.","JPN":"やっと来たか。","ENG":"Took you long enough.","TWN":"現在才回來？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"또 혼자서 침식지대에 다녀온 거냐?","JPN":"また一人で侵食地帯に行ってきたのか？","ENG":"Did you go into the Corrupted Area all by yourself again?","TWN":"又一個人去了侵蝕區嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"카운터가 무적인것도 아닌데, 대단한 배짱이군.","JPN":"カウンタ―とは言え無敵なわけでもないのに、大した度胸だ。","ENG":"Counters aren't invincible, you know. You got guts.","TWN":"制裁者也不是無敵的，膽子可真大。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"먹고 살려면 어쩔 수 없죠. 침식지대에 저만 가는것도 아니구요.","JPN":"生活のためには仕方ないでしょう。侵食地帯に行ってるのも、私だけじゃないですし。","ENG":"I need to make a living, you know. Plus, I'm not the only one who goes into the Corrupted Area.","TWN":"嘿嘿，為了生計沒辦法啊。而且去侵蝕區的也不止我一個。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"조심해야 할 거다. 침식체는 사람을 가리지 않아.","JPN":"気をつけろ。侵食体は相手を選ばない。","ENG":"You'd better be careful. C.O.s attack all humans.","TWN":"下次小心點，侵蝕體可不挑人。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BORIS_DOLL_NPC_NULL","text":{"KOREA":"그럼 가져온 물건 좀 볼까?","JPN":"じゃあ、今日の品を見させてもらおう。","ENG":"Then, let's see what you got for me.","TWN":"那看看你帶來的東西吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"네에~ 원하시는 만큼 보세요!","JPN":"は～い！　どうぞどうぞ！","ENG":"Okay! Take your time!","TWN":"好的～隨便看！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"BORIS_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};